mapper.insert:
INSERT INTO follow_up_revisit_request (
    register_id, patient_id, reason, urgency, status
) VALUES (
    #{registerId}, #{patientId}, #{reason}, #{urgency}, COALESCE(#{status}, 'pending')
)

mapper.select:
SELECT r.id AS "id", r.register_id AS "registerId", r.patient_id AS "patientId", r.reason AS "reason", r.urgency AS "urgency", r.status AS "status", r.created_at AS "createdAt" FROM follow_up_revisit_request r WHERE r.register_id = #{registerId}
AND r.status = #{status}
ORDER BY r.created_at DESC

SELECT r.id AS "id", r.register_id AS "registerId", r.patient_id AS "patientId", r.reason AS "reason", r.urgency AS "urgency", r.status AS "status", r.created_at AS "createdAt", reg.case_number AS "caseNumber", reg.real_name AS "patientName" FROM follow_up_revisit_request r INNER JOIN register reg ON reg.id = r.register_id LEFT JOIN follow_up_enrollment fe ON fe.register_id = r.register_id WHERE r.status = 'pending'
AND fe.managing_department_id = #{departmentId}
ORDER BY CASE r.urgency WHEN 'urgent' THEN 0 ELSE 1 END, r.created_at DESC
